import React from 'react';

const Hero = ({ content = {} }) => {
  const {
    title = 'Services d\'Électricien Professionnel',
    subtitle = 'Déposez votre projet et recevez des devis d\'artisans qualifiés près de chez vous',
    ctaText = 'Devis Gratuit',
    ctaLink = '#contact'
  } = content;

  return (
    <section className="hero">
      <div className="container">
        <div className="hero-content">
          <h1>{title}</h1>
          <p>{subtitle}</p>
          <form className="hero-form">
            <input type="text" placeholder="Votre code postal" required />
            <select required>
              <option value="">Type de projet</option>
              <option value="installation">Nouvelle installation</option>
              <option value="renovation">Rénovation</option>
              <option value="reparation">Réparation</option>
            </select>
            <button type="submit">{ctaText}</button>
          </form>
        </div>
      </div>
    </section>
  );
};

export default Hero;
